var COURSE_PL_FR = [{day: 1, title: `Pierwsze powitania`, title_native: `Premières salutations`, focus: `Zaczynasz podróż w Paryżu i uczysz się najprostszych zwrotów, które przydadzą się w hotelu, sklepie i kawiarni. Celem jest brzmieć uprzejmie od pierwszego kontaktu.`, vocab: [{fr: `bonjour`, pl: `dzień dobry`, ipa: `bą-żur`},{fr: `salut`, pl: `cześć`, ipa: `sa-lu`},{fr: `au revoir`, pl: `do widzenia`, ipa: `o rwu-ar`},{fr: `merci`, pl: `dziękuję`, ipa: `mer-si`},{fr: `s’il vous plaît`, pl: `proszę`, ipa: `sil wu ple`},{fr: `oui`, pl: `tak`, ipa: `łi`},{fr: `non`, pl: `nie`, ipa: `ną`},{fr: `monsieur`, pl: `pan`, ipa: `mę-sje`},{fr: `madame`, pl: `pani`, ipa: `ma-dam`},{fr: `excusez-moi`, pl: `przepraszam`, ipa: `eks-kiu-ze mła`}], phrases: [{fr: `Bonjour, monsieur.`, pl: `Dzień dobry, proszę pana.`, ipa: `bą-żur mę-sje`},{fr: `Bonjour, madame.`, pl: `Dzień dobry, proszę pani.`, ipa: `bą-żur ma-dam`},{fr: `Merci beaucoup.`, pl: `Bardzo dziękuję.`, ipa: `mer-si bo-ku`},{fr: `S’il vous plaît.`, pl: `Proszę.`, ipa: `sil wu ple`},{fr: `Excusez-moi.`, pl: `Przepraszam.`, ipa: `eks-kiu-ze mła`},{fr: `Au revoir.`, pl: `Do widzenia.`, ipa: `o rwu-ar`}], grammar: `W języku francuskim uprzejmość jest bardzo ważna, zwłaszcza przy pierwszym kontakcie. W sklepie, kawiarni czy recepcji zawsze zacznij od Bonjour, zanim przejdziesz do pytania. Monsieur i madame dodają naturalnej grzeczności.`, practice: [`Powiedz po francusku „Dzień dobry, proszę pani”.`,`Przetłumacz: Merci beaucoup.`,`Wyobraź sobie, że wchodzisz do małej piekarni w Lyonie. Jak się przywitasz?`,`Połącz oui, non, merci z polskimi znaczeniami.`,`Napisz krótką wymianę: dzień dobry, dziękuję, do widzenia.`]},{day: 2, title: `Przedstawianie się`, title_native: `Se présenter`, focus: `Jesteś w hostelu w Marsylii i poznajesz innych podróżnych. Nauczysz się mówić, jak masz na imię, skąd jesteś i że jesteś z Polski.`, vocab: [{fr: `je`, pl: `ja`, ipa: `ży`},{fr: `m’appelle`, pl: `nazywam się`, ipa: `ma-pel`},{fr: `être`, pl: `być`, ipa: `etr`},{fr: `je suis`, pl: `jestem`, ipa: `ży słi`},{fr: `polonais`, pl: `Polak`, ipa: `po-lo-ne`},{fr: `polonaise`, pl: `Polka`, ipa: `po-lo-nez`},{fr: `la Pologne`, pl: `Polska`, ipa: `la po-loń`},{fr: `et`, pl: `i`, ipa: `e`},{fr: `aussi`, pl: `też`, ipa: `o-si`},{fr: `enchanté`, pl: `miło mi`, ipa: `ą-szą-te`}], phrases: [{fr: `Je m’appelle Anna.`, pl: `Nazywam się Anna.`, ipa: `ży ma-pel a-na`},{fr: `Je suis polonais.`, pl: `Jestem Polakiem.`, ipa: `ży słi po-lo-ne`},{fr: `Je suis polonaise.`, pl: `Jestem Polką.`, ipa: `ży słi po-lo-nez`},{fr: `Je viens de Pologne.`, pl: `Pochodzę z Polski.`, ipa: `ży wję dy po-loń`},{fr: `Et vous ?`, pl: `A pan/pani?`, ipa: `e wu`},{fr: `Enchanté.`, pl: `Miło mi.`, ipa: `ą-szą-te`}], grammar: `Je suis oznacza „jestem” i jest jednym z najważniejszych zwrotów na początku nauki. W języku francuskim formy narodowości często zmieniają się zależnie od rodzaju: polonais dla mężczyzny, polonaise dla kobiety. W rozmowie z nieznajomym używaj vous zamiast tu.`, practice: [`Przedstaw się po francusku imieniem.`,`Powiedz: „Jestem z Polski”.`,`Wybierz właściwą formę: polonais czy polonaise.`,`Odpowiedz na pytanie: Et vous ?`,`Ułóż trzy zdania o sobie z Je suis.`]},{day: 3, title: `Liczby od 0 do 20`, title_native: `Les nombres de zéro à vingt`, focus: `W Nicei kupujesz wodę, bilety i małe przekąski. Liczby pomogą ci pytać o ceny, pokoje, adresy i godziny.`, vocab: [{fr: `zéro`, pl: `zero`, ipa: `ze-ro`},{fr: `un`, pl: `jeden`, ipa: `ę`},{fr: `deux`, pl: `dwa`, ipa: `dy`},{fr: `trois`, pl: `trzy`, ipa: `trwa`},{fr: `quatre`, pl: `cztery`, ipa: `katr`},{fr: `cinq`, pl: `pięć`, ipa: `sęk`},{fr: `six`, pl: `sześć`, ipa: `sis`},{fr: `sept`, pl: `siedem`, ipa: `set`},{fr: `huit`, pl: `osiem`, ipa: `łit`},{fr: `dix`, pl: `dziesięć`, ipa: `dis`}], phrases: [{fr: `un café`, pl: `jedna kawa`, ipa: `ę ka-fe`},{fr: `deux billets`, pl: `dwa bilety`, ipa: `dy bi-je`},{fr: `trois euros`, pl: `trzy euro`, ipa: `trwa zy-ro`},{fr: `quatre personnes`, pl: `cztery osoby`, ipa: `katr per-son`},{fr: `cinq minutes`, pl: `pięć minut`, ipa: `sęk mi-nut`},{fr: `Ça fait dix euros.`, pl: `To kosztuje dziesięć euro.`, ipa: `sa fe di zy-ro`}], grammar: `Francuskie liczby często łączą się dźwiękowo z następnym słowem, szczególnie przed samogłoską. Trois euros brzmi jak trwa zy-ro, bo końcowe s przechodzi w dźwięk z. Na początku najważniejsze jest rozumieć liczby w cenach i ilościach.`, practice: [`Policz po francusku od 1 do 10.`,`Powiedz: „dwa bilety”.`,`Przetłumacz: cinq minutes.`,`Wyobraź sobie, że płacisz 10 euro. Co może powiedzieć sprzedawca?`,`Napisz trzy kombinacje liczby i rzeczownika, np. jedna kawa.`]},{day: 4, title: `Uprzejme pytania i podstawowe prośby`, title_native: `Questions polies et demandes simples`, focus: `Jesteś w informacji turystycznej w Brukseli i potrzebujesz mapy oraz pomocy. Nauczysz się prosić grzecznie i używać prostych pytań.`, vocab: [{fr: `où`, pl: `gdzie`, ipa: `u`},{fr: `quoi`, pl: `co`, ipa: `kła`},{fr: `quand`, pl: `kiedy`, ipa: `ką`},{fr: `comment`, pl: `jak`, ipa: `ko-mą`},{fr: `une carte`, pl: `mapa`, ipa: `iun kart`},{fr: `un plan`, pl: `plan miasta`, ipa: `ę plą`},{fr: `aider`, pl: `pomagać`, ipa: `e-de`},{fr: `possible`, pl: `możliwe`, ipa: `po-si-bl`},{fr: `ici`, pl: `tutaj`, ipa: `i-si`},{fr: `là`, pl: `tam`, ipa: `la`}], phrases: [{fr: `Où est la gare ?`, pl: `Gdzie jest dworzec?`, ipa: `u e la gar`},{fr: `Je voudrais une carte.`, pl: `Chciałbym mapę.`, ipa: `ży wu-dre iun kart`},{fr: `C’est possible ?`, pl: `Czy to możliwe?`, ipa: `se po-si-bl`},{fr: `Vous pouvez m’aider ?`, pl: `Czy może mi pan/pani pomóc?`, ipa: `wu pu-we me-de`},{fr: `C’est ici ?`, pl: `Czy to tutaj?`, ipa: `se i-si`},{fr: `C’est là.`, pl: `To tam.`, ipa: `se la`}], grammar: `Je voudrais oznacza „chciałbym/chciałabym” i jest bardzo przydatne w podróży. Jest bardziej uprzejme niż je veux, czyli „chcę”. W miejscach publicznych używaj konstrukcji Vous pouvez…? aby prosić o pomoc.`, practice: [`Poproś po francusku o mapę.`,`Zapytaj: „Gdzie jest dworzec?”`,`Przetłumacz: Vous pouvez m’aider ?`,`Wskaż różnicę między ici i là.`,`Ułóż pytanie z comment.`]},{day: 5, title: `W kawiarni`, title_native: `Au café`, focus: `Siedzisz w kawiarni w Montmartre i zamawiasz kawę oraz rogalika. Nauczysz się prostego, naturalnego języka do zamawiania.`, vocab: [{fr: `un café`, pl: `kawa`, ipa: `ę ka-fe`},{fr: `un thé`, pl: `herbata`, ipa: `ę te`},{fr: `un croissant`, pl: `rogalik`, ipa: `ę kru-a-są`},{fr: `une baguette`, pl: `bagietka`, ipa: `iun ba-get`},{fr: `un verre d’eau`, pl: `szklanka wody`, ipa: `ę wer do`},{fr: `l’addition`, pl: `rachunek`, ipa: `la-di-sją`},{fr: `chaud`, pl: `gorący`, ipa: `szo`},{fr: `froid`, pl: `zimny`, ipa: `frła`},{fr: `avec`, pl: `z`, ipa: `a-wek`},{fr: `sans`, pl: `bez`, ipa: `są`}], phrases: [{fr: `Un café, s’il vous plaît.`, pl: `Kawę, proszę.`, ipa: `ę ka-fe sil wu ple`},{fr: `Je voudrais un croissant.`, pl: `Chciałbym rogalika.`, ipa: `ży wu-dre ę kru-a-są`},{fr: `Avec du lait.`, pl: `Z mlekiem.`, ipa: `a-wek dy le`},{fr: `Sans sucre.`, pl: `Bez cukru.`, ipa: `są siukr`},{fr: `L’addition, s’il vous plaît.`, pl: `Rachunek, proszę.`, ipa: `la-di-sją sil wu ple`},{fr: `Un verre d’eau, s’il vous plaît.`, pl: `Szklankę wody, proszę.`, ipa: `ę wer do sil wu ple`}], grammar: `We francuskich zamówieniach często wystarczy rzeczownik z s’il vous plaît. Jednak Je voudrais brzmi pełniej i uprzejmiej. Avec oznacza „z”, a sans oznacza „bez”, więc możesz łatwo dopasować zamówienie do siebie.`, practice: [`Zamów kawę po francusku.`,`Powiedz: „bez cukru”.`,`Poproś o rachunek.`,`Przetłumacz: Je voudrais un croissant.`,`Napisz swoje idealne zamówienie w kawiarni.`]},{day: 6, title: `Ceny i płatność`, title_native: `Les prix et le paiement`, focus: `Kupujesz pamiątki w Strasburgu i pytasz o cenę. Nauczysz się rozumieć podstawowe zwroty przy kasie.`, vocab: [{fr: `combien`, pl: `ile`, ipa: `ką-bję`},{fr: `ça coûte`, pl: `to kosztuje`, ipa: `sa kut`},{fr: `euro`, pl: `euro`, ipa: `y-ro`},{fr: `cher`, pl: `drogi`, ipa: `szer`},{fr: `pas cher`, pl: `niedrogi`, ipa: `pa szer`},{fr: `payer`, pl: `płacić`, ipa: `pe-je`},{fr: `la carte`, pl: `karta`, ipa: `la kart`},{fr: `en espèces`, pl: `gotówką`, ipa: `ą nes-pes`},{fr: `le reçu`, pl: `paragon`, ipa: `ly ry-siu`},{fr: `la monnaie`, pl: `reszta`, ipa: `la mo-ne`}], phrases: [{fr: `Combien ça coûte ?`, pl: `Ile to kosztuje?`, ipa: `ką-bję sa kut`},{fr: `C’est combien ?`, pl: `Ile to jest?`, ipa: `se ką-bję`},{fr: `Je paie par carte.`, pl: `Płacę kartą.`, ipa: `ży pe par kart`},{fr: `Je paie en espèces.`, pl: `Płacę gotówką.`, ipa: `ży pe ą nes-pes`},{fr: `Vous avez la monnaie ?`, pl: `Ma pan/pani resztę?`, ipa: `wu za-we la mo-ne`},{fr: `Je voudrais le reçu.`, pl: `Chciałbym paragon.`, ipa: `ży wu-dre ly ry-siu`}], grammar: `Pytanie Combien ça coûte ? jest bardzo praktyczne i działa w sklepach, na targu i w kiosku. Par carte oznacza „kartą”, a en espèces „gotówką”. We Francji terminale płatnicze są powszechne, ale na małych targach warto mieć trochę gotówki.`, practice: [`Zapytaj o cenę pamiątki.`,`Powiedz, że płacisz kartą.`,`Przetłumacz: pas cher.`,`Poproś o paragon.`,`Ułóż krótką rozmowę przy kasie.`]},{day: 7, title: `Kierunki w mieście`, title_native: `Les directions en ville`, focus: `Spacerujesz po Genewie i pytasz o drogę do muzeum. Nauczysz się rozumieć podstawowe wskazówki: w lewo, w prawo, prosto.`, vocab: [{fr: `à gauche`, pl: `w lewo`, ipa: `a gosz`},{fr: `à droite`, pl: `w prawo`, ipa: `a drłat`},{fr: `tout droit`, pl: `prosto`, ipa: `tu drła`},{fr: `près de`, pl: `blisko`, ipa: `pre dy`},{fr: `loin de`, pl: `daleko od`, ipa: `lwę dy`},{fr: `la rue`, pl: `ulica`, ipa: `la riu`},{fr: `la place`, pl: `plac`, ipa: `la plas`},{fr: `le pont`, pl: `most`, ipa: `ly pą`},{fr: `le musée`, pl: `muzeum`, ipa: `ly miu-ze`},{fr: `la gare`, pl: `dworzec`, ipa: `la gar`}], phrases: [{fr: `Où est le musée ?`, pl: `Gdzie jest muzeum?`, ipa: `u e ly miu-ze`},{fr: `Tournez à gauche.`, pl: `Proszę skręcić w lewo.`, ipa: `tur-ne a gosz`},{fr: `Tournez à droite.`, pl: `Proszę skręcić w prawo.`, ipa: `tur-ne a drłat`},{fr: `Allez tout droit.`, pl: `Proszę iść prosto.`, ipa: `a-le tu drła`},{fr: `C’est près d’ici.`, pl: `To jest blisko stąd.`, ipa: `se pre di-si`},{fr: `C’est loin ?`, pl: `Czy to daleko?`, ipa: `se lwę`}], grammar: `Tryb rozkazujący jest często używany w instrukcjach: allez, tournez. Nie musisz go aktywnie odmieniać na początku; wystarczy rozpoznawać najczęstsze formy. D’ici znaczy „stąd”, więc près d’ici to „blisko stąd”.`, practice: [`Zapytaj, gdzie jest dworzec.`,`Przetłumacz: Allez tout droit.`,`Powiedz: „To jest blisko stąd”.`,`Zapisz trzy kierunki po francusku.`,`Wyobraź sobie trasę do kawiarni i opisz ją dwoma zdaniami.`]},{day: 8, title: `Transport publiczny`, title_native: `Les transports publics`, focus: `Kupujesz bilet na metro w Paryżu i pytasz o właściwą linię. Nauczysz się słów związanych z metrem, autobusem i tramwajem.`, vocab: [{fr: `le métro`, pl: `metro`, ipa: `ly me-tro`},{fr: `le bus`, pl: `autobus`, ipa: `ly bus`},{fr: `le tram`, pl: `tramwaj`, ipa: `ly tram`},{fr: `un billet`, pl: `bilet`, ipa: `ę bi-je`},{fr: `un ticket`, pl: `bilet`, ipa: `ę ti-ke`},{fr: `la ligne`, pl: `linia`, ipa: `la liń`},{fr: `la station`, pl: `stacja`, ipa: `la sta-sją`},{fr: `l’arrêt`, pl: `przystanek`, ipa: `la-re`},{fr: `aller`, pl: `jechać/iść`, ipa: `a-le`},{fr: `descendre`, pl: `wysiadać`, ipa: `de-sądr`}], phrases: [{fr: `Je voudrais un billet.`, pl: `Chciałbym bilet.`, ipa: `ży wu-dre ę bi-je`},{fr: `Quelle ligne pour le centre ?`, pl: `Która linia do centrum?`, ipa: `kel liń pur ly sątr`},{fr: `Où est la station ?`, pl: `Gdzie jest stacja?`, ipa: `u e la sta-sją`},{fr: `Je dois descendre où ?`, pl: `Gdzie muszę wysiąść?`, ipa: `ży dwa de-sądr u`},{fr: `C’est direct ?`, pl: `Czy to bezpośrednio?`, ipa: `se di-rekt`},{fr: `Le bus arrive quand ?`, pl: `Kiedy przyjeżdża autobus?`, ipa: `ly bus a-riw ką`}], grammar: `Quelle oznacza „która” przy rzeczownikach rodzaju żeńskiego, takich jak ligne. Pytanie pour le centre znaczy dosłownie „dla/do centrum” i jest krótkim sposobem pytania o kierunek. W transporcie przydatne jest też C’est direct ?, czyli „Czy to jest bezpośrednio?”.`, practice: [`Poproś o jeden bilet.`,`Zapytaj, która linia jedzie do centrum.`,`Przetłumacz: Je dois descendre où ?`,`Napisz trzy słowa związane z transportem.`,`Ułóż krótkie pytanie o autobus.`]},{day: 9, title: `Hotel i zakwaterowanie`, title_native: `À l’hôtel`, focus: `Meldujesz się w hotelu w Quebecu i potrzebujesz pokoju, klucza oraz hasła do Wi-Fi. Nauczysz się typowych zwrotów recepcyjnych.`, vocab: [{fr: `l’hôtel`, pl: `hotel`, ipa: `lo-tel`},{fr: `la réception`, pl: `recepcja`, ipa: `la re-sep-sją`},{fr: `une chambre`, pl: `pokój`, ipa: `iun sząbr`},{fr: `la clé`, pl: `klucz`, ipa: `la kle`},{fr: `la réservation`, pl: `rezerwacja`, ipa: `la re-zer-wa-sją`},{fr: `le passeport`, pl: `paszport`, ipa: `ly pas-por`},{fr: `le nom`, pl: `nazwisko`, ipa: `ly ną`},{fr: `le petit-déjeuner`, pl: `śniadanie`, ipa: `ly py-ti de-ży-ne`},{fr: `le Wi-Fi`, pl: `Wi-Fi`, ipa: `ly łi-fi`},{fr: `la nuit`, pl: `noc`, ipa: `la nui`}], phrases: [{fr: `J’ai une réservation.`, pl: `Mam rezerwację.`, ipa: `że iun re-zer-wa-sją`},{fr: `À quel nom ?`, pl: `Na jakie nazwisko?`, ipa: `a kel ną`},{fr: `Voici mon passeport.`, pl: `Oto mój paszport.`, ipa: `wła-si mą pas-por`},{fr: `La chambre est prête ?`, pl: `Czy pokój jest gotowy?`, ipa: `la sząbr e pret`},{fr: `Quel est le mot de passe du Wi-Fi ?`, pl: `Jakie jest hasło do Wi-Fi?`, ipa: `kel e ly mo dy pas dy łi-fi`},{fr: `Le petit-déjeuner est inclus ?`, pl: `Czy śniadanie jest wliczone?`, ipa: `ly py-ti de-ży-ne e ę-kliu`}], grammar: `J’ai oznacza „mam” i przyda się w hotelu, sklepie i aptece. Francuskie une chambre oznacza pokój hotelowy, a nie tylko dowolne pomieszczenie. Przy meldowaniu często usłyszysz À quel nom ?, czyli „Na jakie nazwisko?”.`, practice: [`Powiedz, że masz rezerwację.`,`Zapytaj o hasło do Wi-Fi.`,`Przetłumacz: Voici mon passeport.`,`Zapytaj, czy śniadanie jest wliczone.`,`Napisz krótką rozmowę z recepcjonistą.`]},{day: 10, title: `Czas i godziny`, title_native: `L’heure et les horaires`, focus: `Planujesz dzień w Lozannie i pytasz o godziny otwarcia muzeum oraz odjazdu pociągu. Nauczysz się mówić o czasie w praktycznych sytuacjach.`, vocab: [{fr: `l’heure`, pl: `godzina`, ipa: `ler`},{fr: `maintenant`, pl: `teraz`, ipa: `męt-ną`},{fr: `aujourd’hui`, pl: `dzisiaj`, ipa: `o-żur-dłi`},{fr: `demain`, pl: `jutro`, ipa: `dy-mę`},{fr: `matin`, pl: `rano`, ipa: `ma-tę`},{fr: `après-midi`, pl: `popołudnie`, ipa: `a-pre mi-di`},{fr: `soir`, pl: `wieczór`, ipa: `słar`},{fr: `ouvert`, pl: `otwarty`, ipa: `u-wer`},{fr: `fermé`, pl: `zamknięty`, ipa: `fer-me`},{fr: `tard`, pl: `późno`, ipa: `tar`}], phrases: [{fr: `Quelle heure est-il ?`, pl: `Która jest godzina?`, ipa: `kel er e til`},{fr: `Il est neuf heures.`, pl: `Jest dziewiąta.`, ipa: `il e nef er`},{fr: `C’est ouvert ?`, pl: `Czy jest otwarte?`, ipa: `se u-wer`},{fr: `C’est fermé aujourd’hui.`, pl: `Dzisiaj jest zamknięte.`, ipa: `se fer-me o-żur-dłi`},{fr: `À quelle heure ça ouvre ?`, pl: `O której to się otwiera?`, ipa: `a kel er sa uwr`},{fr: `Le train part à dix heures.`, pl: `Pociąg odjeżdża o dziesiątej.`, ipa: `ly trę par a di zer`}], grammar: `Do podawania godziny używa się Il est. Przy godzinach pełnych mówimy neuf heures, dix heures. Pytanie À quelle heure…? oznacza „O której godzinie…?” i jest bardzo przydatne przy planowaniu.`, practice: [`Zapytaj, która jest godzina.`,`Powiedz: „Jest dziewiąta”.`,`Zapytaj, o której otwiera się muzeum.`,`Przetłumacz: C’est fermé aujourd’hui.`,`Napisz plan dnia z trzema godzinami po francusku.`]},{day: 11, title: `Jedzenie i menu`, title_native: `La nourriture et le menu`, focus: `Czytasz menu w restauracji w Bordeaux. Nauczysz się nazw podstawowych dań i zwrotów, które pomagają wybrać posiłek.`, vocab: [{fr: `le menu`, pl: `menu`, ipa: `ly my-ni`},{fr: `l’entrée`, pl: `przystawka`, ipa: `lą-tre`},{fr: `le plat`, pl: `danie główne`, ipa: `ly pla`},{fr: `le dessert`, pl: `deser`, ipa: `ly de-ser`},{fr: `la soupe`, pl: `zupa`, ipa: `la sup`},{fr: `le poisson`, pl: `ryba`, ipa: `ly pła-są`},{fr: `la viande`, pl: `mięso`, ipa: `la wi-ąd`},{fr: `le poulet`, pl: `kurczak`, ipa: `ly pu-le`},{fr: `les légumes`, pl: `warzywa`, ipa: `le le-gium`},{fr: `le fromage`, pl: `ser`, ipa: `ly fro-maż`}], phrases: [{fr: `Je voudrais voir le menu.`, pl: `Chciałbym zobaczyć menu.`, ipa: `ży wu-dre włar ly my-ni`},{fr: `Qu’est-ce que vous recommandez ?`, pl: `Co pan/pani poleca?`, ipa: `kes ky wu ry-ko-mą-de`},{fr: `Je prends le poulet.`, pl: `Biorę kurczaka.`, ipa: `ży prą ly pu-le`},{fr: `C’est avec des légumes ?`, pl: `Czy to jest z warzywami?`, ipa: `se a-wek de le-gium`},{fr: `Je ne mange pas de viande.`, pl: `Nie jem mięsa.`, ipa: `ży ny mąż pa dy wi-ąd`},{fr: `C’était très bon.`, pl: `To było bardzo dobre.`, ipa: `se-te tre bą`}], grammar: `Je prends oznacza „biorę” i jest naturalnym sposobem zamawiania jedzenia. Francuskie de pojawia się często po przeczeniach, np. Je ne mange pas de viande. Przy wyborze dania możesz też użyć prostego Je voudrais.`, practice: [`Poproś o menu.`,`Powiedz, że bierzesz kurczaka.`,`Zapytaj, co kelner poleca.`,`Przetłumacz: Je ne mange pas de viande.`,`Wybierz przystawkę, danie i deser po francusku.`]},{day: 12, title: `Preferencje i alergie`, title_native: `Préférences et allergies`, focus: `Jesz obiad w Lyonie i musisz powiedzieć o alergii lub preferencjach żywieniowych. Nauczysz się jasno komunikować potrzeby bez długich wyjaśnień.`, vocab: [{fr: `allergique`, pl: `uczulony`, ipa: `a-ler-żik`},{fr: `une allergie`, pl: `alergia`, ipa: `iun a-ler-żi`},{fr: `sans gluten`, pl: `bez glutenu`, ipa: `są gliu-ten`},{fr: `sans lactose`, pl: `bez laktozy`, ipa: `są lak-toz`},{fr: `végétarien`, pl: `wegetariański`, ipa: `we-że-ta-rję`},{fr: `végétarienne`, pl: `wegetariańska`, ipa: `we-że-ta-rjen`},{fr: `épicé`, pl: `pikantny`, ipa: `e-pi-se`},{fr: `sucré`, pl: `słodki`, ipa: `siu-kre`},{fr: `salé`, pl: `słony`, ipa: `sa-le`},{fr: `léger`, pl: `lekki`, ipa: `le-że`}], phrases: [{fr: `Je suis allergique aux noix.`, pl: `Jestem uczulony na orzechy.`, ipa: `ży słi a-ler-żik o nwa`},{fr: `Sans gluten, s’il vous plaît.`, pl: `Bez glutenu, proszę.`, ipa: `są gliu-ten sil wu ple`},{fr: `C’est épicé ?`, pl: `Czy to jest pikantne?`, ipa: `se e-pi-se`},{fr: `Je suis végétarien.`, pl: `Jestem wegetarianinem.`, ipa: `ży słi we-że-ta-rję`},{fr: `Je suis végétarienne.`, pl: `Jestem wegetarianką.`, ipa: `ży słi we-że-ta-rjen`},{fr: `Vous avez une option légère ?`, pl: `Czy macie lekką opcję?`, ipa: `wu za-we iun op-sją le-żer`}], grammar: `Przy alergiach używaj Je suis allergique à… i dodaj składnik. Aux noix oznacza „na orzechy”, bo à + les tworzy aux. W restauracji lepiej mówić prosto i konkretnie, aby uniknąć nieporozumień.`, practice: [`Powiedz, że jesteś uczulony na orzechy.`,`Zapytaj, czy danie jest pikantne.`,`Poproś o opcję bez glutenu.`,`Wybierz właściwą formę: végétarien czy végétarienne.`,`Napisz dwie rzeczy, których nie jesz, używając sans.`]},{day: 13, title: `Zakupy odzieżowe`, title_native: `Acheter des vêtements`, focus: `Przymierzasz ubrania w sklepie w Lille. Nauczysz się pytać o rozmiar, kolor i możliwość przymierzenia.`, vocab: [{fr: `un magasin`, pl: `sklep`, ipa: `ę ma-ga-zę`},{fr: `un vêtement`, pl: `ubranie`, ipa: `ę wet-mą`},{fr: `une chemise`, pl: `koszula`, ipa: `iun szy-miz`},{fr: `un pantalon`, pl: `spodnie`, ipa: `ę pą-ta-lą`},{fr: `une robe`, pl: `sukienka`, ipa: `iun rob`},{fr: `des chaussures`, pl: `buty`, ipa: `de szo-siur`},{fr: `la taille`, pl: `rozmiar`, ipa: `la taj`},{fr: `la couleur`, pl: `kolor`, ipa: `la ku-ler`},{fr: `cher`, pl: `drogi`, ipa: `szer`},{fr: `essayer`, pl: `przymierzyć`, ipa: `e-se-je`}], phrases: [{fr: `Je peux essayer ?`, pl: `Czy mogę przymierzyć?`, ipa: `ży py e-se-je`},{fr: `Vous avez ma taille ?`, pl: `Czy macie mój rozmiar?`, ipa: `wu za-we ma taj`},{fr: `C’est trop grand.`, pl: `To jest za duże.`, ipa: `se tro grą`},{fr: `C’est trop petit.`, pl: `To jest za małe.`, ipa: `se tro py-ti`},{fr: `Vous avez une autre couleur ?`, pl: `Czy macie inny kolor?`, ipa: `wu za-we iun otr ku-ler`},{fr: `Je le prends.`, pl: `Biorę to.`, ipa: `ży ly prą`}], grammar: `Trop oznacza „za bardzo” lub „zbyt”, np. trop grand, trop petit. Je le prends znaczy „biorę to” i odnosi się do rzeczy rodzaju męskiego; w praktyce w sklepie zostaniesz dobrze zrozumiany. Przy pytaniu o rozmiar użyj Vous avez ma taille ?`, practice: [`Zapytaj, czy możesz przymierzyć.`,`Powiedz, że coś jest za małe.`,`Zapytaj o inny kolor.`,`Przetłumacz: Je le prends.`,`Napisz mini-dialog w sklepie z ubraniami.`]},{day: 14, title: `Targ i produkty spożywcze`, title_native: `Au marché`, focus: `Kupujesz świeże produkty na targu w Aix-en-Provence. Nauczysz się prosić o ilości i rozumieć podstawowe nazwy owoców oraz warzyw.`, vocab: [{fr: `le marché`, pl: `targ`, ipa: `ly mar-sze`},{fr: `les fruits`, pl: `owoce`, ipa: `le frui`},{fr: `les légumes`, pl: `warzywa`, ipa: `le le-gium`},{fr: `une pomme`, pl: `jabłko`, ipa: `iun pom`},{fr: `une banane`, pl: `banan`, ipa: `iun ba-nan`},{fr: `une tomate`, pl: `pomidor`, ipa: `iun to-mat`},{fr: `du pain`, pl: `chleb`, ipa: `dy pę`},{fr: `du fromage`, pl: `ser`, ipa: `dy fro-maż`},{fr: `un kilo`, pl: `kilogram`, ipa: `ę ki-lo`},{fr: `frais`, pl: `świeży`, ipa: `fre`}], phrases: [{fr: `Je voudrais un kilo de tomates.`, pl: `Chciałbym kilogram pomidorów.`, ipa: `ży wu-dre ę ki-lo dy to-mat`},{fr: `C’est frais ?`, pl: `Czy to jest świeże?`, ipa: `se fre`},{fr: `Deux pommes, s’il vous plaît.`, pl: `Dwa jabłka, proszę.`, ipa: `dy pom sil wu ple`},{fr: `Je prends aussi du fromage.`, pl: `Wezmę też ser.`, ipa: `ży prą o-si dy fro-maż`},{fr: `C’est tout.`, pl: `To wszystko.`, ipa: `se tu`},{fr: `Combien je vous dois ?`, pl: `Ile jestem winien?`, ipa: `ką-bję ży wu dwa`}], grammar: `Przy produktach spożywczych często używa się du, de la, des, gdy mówimy o nieokreślonej ilości. Du fromage oznacza „trochę sera” lub po prostu „ser” jako produkt. C’est tout to bardzo naturalny sposób zakończenia zamówienia na targu.`, practice: [`Poproś o kilogram pomidorów.`,`Powiedz: „To wszystko”.`,`Zapytaj, czy owoce są świeże.`,`Przetłumacz: Je prends aussi du fromage.`,`Zrób listę zakupów z pięciu produktów po francusku.`]},{day: 15, title: `Rodzina i ludzie`, title_native: `La famille et les personnes`, focus: `Rozmawiasz z poznaną osobą w kawiarni w Nantes. Nauczysz się mówić o rodzinie i zadawać proste pytania osobiste.`, vocab: [{fr: `la famille`, pl: `rodzina`, ipa: `la fa-mi`},{fr: `la mère`, pl: `matka`, ipa: `la mer`},{fr: `le père`, pl: `ojciec`, ipa: `ly per`},{fr: `la sœur`, pl: `siostra`, ipa: `la ser`},{fr: `le frère`, pl: `brat`, ipa: `ly frer`},{fr: `un ami`, pl: `przyjaciel`, ipa: `ę na-mi`},{fr: `une amie`, pl: `przyjaciółka`, ipa: `iun na-mi`},{fr: `les enfants`, pl: `dzieci`, ipa: `le zą-fą`},{fr: `marié`, pl: `żonaty/zamężna`, ipa: `ma-rje`},{fr: `célibataire`, pl: `singiel`, ipa: `se-li-ba-ter`}], phrases: [{fr: `Vous avez de la famille ici ?`, pl: `Czy ma pan/pani tutaj rodzinę?`, ipa: `wu za-we dy la fa-mi i-si`},{fr: `J’ai un frère.`, pl: `Mam brata.`, ipa: `że ę frer`},{fr: `J’ai une sœur.`, pl: `Mam siostrę.`, ipa: `że iun ser`},{fr: `Je voyage avec un ami.`, pl: `Podróżuję z przyjacielem.`, ipa: `ży wua-jaż a-wek ę na-mi`},{fr: `Je suis célibataire.`, pl: `Jestem singlem/singielką.`, ipa: `ży słi se-li-ba-ter`},{fr: `Ma famille est en Pologne.`, pl: `Moja rodzina jest w Polsce.`, ipa: `ma fa-mi e ą po-loń`}], grammar: `W języku francuskim zaimki dzierżawcze zmieniają się zależnie od rzeczownika: ma famille, mon frère, ma sœur. J’ai oznacza „mam”, więc możesz szybko tworzyć zdania o rodzinie. W rozmowach towarzyskich zachowaj lekki ton i nie pytaj zbyt bezpośrednio o prywatne sprawy.`, practice: [`Powiedz, że masz brata.`,`Powiedz, że twoja rodzina jest w Polsce.`,`Przetłumacz: Je voyage avec un ami.`,`Zapytaj kogoś, czy ma rodzinę tutaj.`,`Napisz trzy zdania o swojej rodzinie.`]},{day: 16, title: `Pogoda i plany dnia`, title_native: `La météo et les projets`, focus: `Planujesz zwiedzanie w Montpellier i sprawdzasz pogodę. Nauczysz się mówić, czy jest ciepło, zimno, słonecznie lub deszczowo.`, vocab: [{fr: `la météo`, pl: `pogoda`, ipa: `la me-te-o`},{fr: `le soleil`, pl: `słońce`, ipa: `ly so-lej`},{fr: `la pluie`, pl: `deszcz`, ipa: `la plui`},{fr: `le vent`, pl: `wiatr`, ipa: `ly wą`},{fr: `chaud`, pl: `ciepło`, ipa: `szo`},{fr: `froid`, pl: `zimno`, ipa: `frła`},{fr: `nuageux`, pl: `pochmurno`, ipa: `nua-ży`},{fr: `beau`, pl: `ładnie`, ipa: `bo`},{fr: `mauvais`, pl: `zły`, ipa: `mo-we`},{fr: `un parapluie`, pl: `parasol`, ipa: `ę pa-ra-plui`}], phrases: [{fr: `Il fait beau.`, pl: `Jest ładna pogoda.`, ipa: `il fe bo`},{fr: `Il fait chaud.`, pl: `Jest ciepło.`, ipa: `il fe szo`},{fr: `Il fait froid.`, pl: `Jest zimno.`, ipa: `il fe frła`},{fr: `Il pleut.`, pl: `Pada deszcz.`, ipa: `il ply`},{fr: `Il y a du vent.`, pl: `Jest wiatr.`, ipa: `il ja dy wą`},{fr: `Je prends un parapluie.`, pl: `Biorę parasol.`, ipa: `ży prą ę pa-ra-plui`}], grammar: `Do opisu pogody często używa się konstrukcji Il fait…, np. Il fait chaud. Il pleut oznacza „pada deszcz” i nie wymaga dodatkowego rzeczownika. Il y a oznacza „jest/są” i przydaje się w zwrocie Il y a du vent.`, practice: [`Powiedz, że jest ładna pogoda.`,`Powiedz, że pada deszcz.`,`Przetłumacz: Je prends un parapluie.`,`Opisz dzisiejszą pogodę po francusku.`,`Napisz plan dnia zależny od pogody.`]},{day: 17, title: `Atrakcje turystyczne`, title_native: `Les attractions touristiques`, focus: `Zwiedzasz Paryż i chcesz odwiedzić muzeum, katedrę oraz punkt widokowy. Nauczysz się pytać o bilety, godziny i wejście.`, vocab: [{fr: `une attraction`, pl: `atrakcja`, ipa: `iun a-trak-sją`},{fr: `un monument`, pl: `zabytek`, ipa: `ę mo-niu-mą`},{fr: `une cathédrale`, pl: `katedra`, ipa: `iun ka-te-dral`},{fr: `une visite`, pl: `zwiedzanie`, ipa: `iun wi-zit`},{fr: `un guide`, pl: `przewodnik`, ipa: `ę gid`},{fr: `l’entrée`, pl: `wejście`, ipa: `lą-tre`},{fr: `la sortie`, pl: `wyjście`, ipa: `la sor-ti`},{fr: `un billet`, pl: `bilet`, ipa: `ę bi-je`},{fr: `gratuit`, pl: `darmowy`, ipa: `gra-tui`},{fr: `la vue`, pl: `widok`, ipa: `la wiu`}], phrases: [{fr: `Où est l’entrée ?`, pl: `Gdzie jest wejście?`, ipa: `u e lą-tre`},{fr: `Il faut un billet ?`, pl: `Czy potrzebny jest bilet?`, ipa: `il fo ę bi-je`},{fr: `C’est gratuit ?`, pl: `Czy to jest darmowe?`, ipa: `se gra-tui`},{fr: `La visite dure combien de temps ?`, pl: `Ile trwa zwiedzanie?`, ipa: `la wi-zit diur ką-bję dy tą`},{fr: `Je voudrais un guide audio.`, pl: `Chciałbym audioprzewodnik.`, ipa: `ży wu-dre ę gid o-djo`},{fr: `La vue est magnifique.`, pl: `Widok jest wspaniały.`, ipa: `la wiu e ma-ńi-fik`}], grammar: `Il faut oznacza „trzeba” lub „potrzebne jest”. To bardzo wygodna konstrukcja: Il faut un billet ? znaczy „Czy trzeba mieć bilet?”. W muzeach i zabytkach często zobaczysz entrée i sortie na znakach.`, practice: [`Zapytaj, gdzie jest wejście.`,`Zapytaj, czy potrzebny jest bilet.`,`Powiedz, że widok jest wspaniały.`,`Przetłumacz: C’est gratuit ?`,`Ułóż plan zwiedzania z trzema atrakcjami.`]},{day: 18, title: `Problemy i pomoc`, title_native: `Problèmes et aide`, focus: `Gubisz się w centrum Brukseli i potrzebujesz pomocy. Nauczysz się jasno powiedzieć, że masz problem, czego szukasz i że nie rozumiesz.`, vocab: [{fr: `un problème`, pl: `problem`, ipa: `ę pro-blem`},{fr: `perdu`, pl: `zgubiony`, ipa: `per-diu`},{fr: `perdue`, pl: `zgubiona`, ipa: `per-diu`},{fr: `aide`, pl: `pomoc`, ipa: `ed`},{fr: `chercher`, pl: `szukać`, ipa: `szer-sze`},{fr: `comprendre`, pl: `rozumieć`, ipa: `ką-prądr`},{fr: `lentement`, pl: `powoli`, ipa: `ląt-mą`},{fr: `répéter`, pl: `powtórzyć`, ipa: `re-pe-te`},{fr: `important`, pl: `ważny`, ipa: `ę-por-tą`},{fr: `urgent`, pl: `pilny`, ipa: `iur-żą`}], phrases: [{fr: `J’ai un problème.`, pl: `Mam problem.`, ipa: `że ę pro-blem`},{fr: `Je suis perdu.`, pl: `Zgubiłem się.`, ipa: `ży słi per-diu`},{fr: `Je suis perdue.`, pl: `Zgubiłam się.`, ipa: `ży słi per-diu`},{fr: `Je cherche mon hôtel.`, pl: `Szukam mojego hotelu.`, ipa: `ży szer-sz mą no-tel`},{fr: `Je ne comprends pas.`, pl: `Nie rozumiem.`, ipa: `ży ny ką-prą pa`},{fr: `Vous pouvez répéter lentement ?`, pl: `Czy może pan/pani powtórzyć powoli?`, ipa: `wu pu-we re-pe-te ląt-mą`}], grammar: `Francuskie przeczenie najczęściej ma dwie części: ne i pas. W mowie potocznej ne bywa pomijane, ale w kursie warto je znać: Je ne comprends pas. Przy przymiotniku perdu/perdue pisownia zmienia się zależnie od rodzaju, choć wymowa jest taka sama.`, practice: [`Powiedz, że masz problem.`,`Powiedz, że nie rozumiesz.`,`Poproś o powtórzenie powoli.`,`Przetłumacz: Je cherche mon hôtel.`,`Napisz krótką sytuację, w której prosisz o pomoc.`]},{day: 19, title: `Apteka i zdrowie`, title_native: `À la pharmacie et la santé`, focus: `Wchodzisz do apteki w Tuluzie, bo boli cię głowa albo gardło. Nauczysz się podstawowych zwrotów medycznych dla podróżnych.`, vocab: [{fr: `la pharmacie`, pl: `apteka`, ipa: `la far-ma-si`},{fr: `un médicament`, pl: `lek`, ipa: `ę me-di-ka-mą`},{fr: `mal`, pl: `ból`, ipa: `mal`},{fr: `la tête`, pl: `głowa`, ipa: `la tet`},{fr: `la gorge`, pl: `gardło`, ipa: `la gorż`},{fr: `le ventre`, pl: `brzuch`, ipa: `ly wątr`},{fr: `la fièvre`, pl: `gorączka`, ipa: `la fje-wr`},{fr: `un rhume`, pl: `przeziębienie`, ipa: `ę rium`},{fr: `un pansement`, pl: `plaster`, ipa: `ę pąs-mą`},{fr: `un médecin`, pl: `lekarz`, ipa: `ę med-sę`}], phrases: [{fr: `J’ai mal à la tête.`, pl: `Boli mnie głowa.`, ipa: `że mal a la tet`},{fr: `J’ai mal à la gorge.`, pl: `Boli mnie gardło.`, ipa: `że mal a la gorż`},{fr: `J’ai de la fièvre.`, pl: `Mam gorączkę.`, ipa: `że dy la fje-wr`},{fr: `Je voudrais quelque chose pour un rhume.`, pl: `Chciałbym coś na przeziębienie.`, ipa: `ży wu-dre kelk szoz pur ę rium`},{fr: `Il me faut un médecin.`, pl: `Potrzebuję lekarza.`, ipa: `il my fo ę med-sę`},{fr: `Vous avez des pansements ?`, pl: `Czy macie plastry?`, ipa: `wu za-we de pąs-mą`}], grammar: `J’ai mal à… oznacza „boli mnie…”. Przed częściami ciała używa się à la, au lub aux, np. à la tête. Il me faut oznacza „potrzebuję” i jest bardzo przydatne, gdy sytuacja jest pilna.`, practice: [`Powiedz, że boli cię głowa.`,`Poproś o coś na przeziębienie.`,`Zapytaj o plastry.`,`Przetłumacz: Il me faut un médecin.`,`Napisz trzy objawy po francusku.`]},{day: 20, title: `Telefon, internet i technologia`, title_native: `Téléphone, Internet et technologie`, focus: `Potrzebujesz karty SIM i internetu w Montrealu. Nauczysz się pytać o Wi-Fi, ładowarkę, telefon i połączenie.`, vocab: [{fr: `le téléphone`, pl: `telefon`, ipa: `ly te-le-fon`},{fr: `Internet`, pl: `internet`, ipa: `ę-ter-net`},{fr: `le Wi-Fi`, pl: `Wi-Fi`, ipa: `ly łi-fi`},{fr: `une carte SIM`, pl: `karta SIM`, ipa: `iun kart sim`},{fr: `un chargeur`, pl: `ładowarka`, ipa: `ę szar-żer`},{fr: `la batterie`, pl: `bateria`, ipa: `la ba-tri`},{fr: `le réseau`, pl: `sieć`, ipa: `ly re-zo`},{fr: `un appel`, pl: `połączenie`, ipa: `ę na-pel`},{fr: `un message`, pl: `wiadomość`, ipa: `ę me-saż`},{fr: `connecté`, pl: `połączony`, ipa: `ko-nek-te`}], phrases: [{fr: `Vous avez le Wi-Fi ?`, pl: `Czy macie Wi-Fi?`, ipa: `wu za-we ly łi-fi`},{fr: `Quel est le mot de passe ?`, pl: `Jakie jest hasło?`, ipa: `kel e ly mo dy pas`},{fr: `Je voudrais une carte SIM.`, pl: `Chciałbym kartę SIM.`, ipa: `ży wu-dre iun kart sim`},{fr: `Ma batterie est faible.`, pl: `Moja bateria jest słaba.`, ipa: `ma ba-tri e febl`},{fr: `Je n’ai pas de réseau.`, pl: `Nie mam sieci.`, ipa: `ży ne pa dy re-zo`},{fr: `Je peux charger mon téléphone ?`, pl: `Czy mogę naładować telefon?`, ipa: `ży py szar-że mą te-le-fon`}], grammar: `Je n’ai pas de… oznacza „nie mam…”. Po przeczeniu często używamy de, np. Je n’ai pas de réseau. Pytanie Je peux…? oznacza „Czy mogę…?” i jest bardzo przydatne przy proszeniu o drobną przysługę.`, practice: [`Zapytaj o hasło do Wi-Fi.`,`Powiedz, że nie masz sieci.`,`Poproś o kartę SIM.`,`Przetłumacz: Je peux charger mon téléphone ?`,`Ułóż dialog w sklepie z telefonami.`]},{day: 21, title: `Pociąg i podróż między miastami`, title_native: `Le train et les voyages entre villes`, focus: `Jedziesz pociągiem z Paryża do Lyonu. Nauczysz się kupować bilet, pytać o peron i mówić o opóźnieniu.`, vocab: [{fr: `le train`, pl: `pociąg`, ipa: `ly trę`},{fr: `la gare`, pl: `dworzec`, ipa: `la gar`},{fr: `le quai`, pl: `peron`, ipa: `ly ke`},{fr: `un aller simple`, pl: `bilet w jedną stronę`, ipa: `ę na-le sępl`},{fr: `un aller-retour`, pl: `bilet tam i z powrotem`, ipa: `ę na-le ry-tur`},{fr: `la destination`, pl: `cel podróży`, ipa: `la des-ti-na-sją`},{fr: `le départ`, pl: `odjazd`, ipa: `ly de-par`},{fr: `l’arrivée`, pl: `przyjazd`, ipa: `la-ri-we`},{fr: `en retard`, pl: `opóźniony`, ipa: `ą ry-tar`},{fr: `à l’heure`, pl: `punktualnie`, ipa: `a ler`}], phrases: [{fr: `Un aller simple pour Lyon.`, pl: `Bilet w jedną stronę do Lyonu.`, ipa: `ę na-le sępl pur li-ją`},{fr: `Un aller-retour pour Paris.`, pl: `Bilet tam i z powrotem do Paryża.`, ipa: `ę na-le ry-tur pur pa-ri`},{fr: `De quel quai part le train ?`, pl: `Z którego peronu odjeżdża pociąg?`, ipa: `dy kel ke par ly trę`},{fr: `Le train est en retard.`, pl: `Pociąg jest opóźniony.`, ipa: `ly trę e ą ry-tar`},{fr: `Le train est à l’heure.`, pl: `Pociąg jest punktualnie.`, ipa: `ly trę e a ler`},{fr: `J’ai raté mon train.`, pl: `Spóźniłem się na pociąg.`, ipa: `że ra-te mą trę`}], grammar: `Pour oznacza „do” w sensie kierunku lub przeznaczenia, np. pour Lyon. Partir oznacza „odjeżdżać” lub „wyjeżdżać”, a forma part pojawia się w pytaniu De quel quai part le train ? W podróży kolejowej quai to jedno z najważniejszych słów.`, practice: [`Kup bilet w jedną stronę do Lyonu.`,`Zapytaj, z którego peronu odjeżdża pociąg.`,`Powiedz, że pociąg jest opóźniony.`,`Przetłumacz: J’ai raté mon train.`,`Napisz krótką rozmowę na dworcu.`]},{day: 22, title: `Wynajem i taksówka`, title_native: `Taxi et location`, focus: `Bierzesz taksówkę w Cannes albo pytasz o wynajem samochodu. Nauczysz się podawać adres, pytać o koszt i czas przejazdu.`, vocab: [{fr: `un taxi`, pl: `taksówka`, ipa: `ę tak-si`},{fr: `une voiture`, pl: `samochód`, ipa: `iun wua-tiur`},{fr: `l’adresse`, pl: `adres`, ipa: `la-dres`},{fr: `le centre-ville`, pl: `centrum miasta`, ipa: `ly sątr-wil`},{fr: `l’aéroport`, pl: `lotnisko`, ipa: `la-e-ro-por`},{fr: `rapide`, pl: `szybki`, ipa: `ra-pid`},{fr: `lent`, pl: `wolny`, ipa: `lą`},{fr: `le prix`, pl: `cena`, ipa: `ly pri`},{fr: `le trajet`, pl: `trasa/przejazd`, ipa: `ly tra-że`},{fr: `la location`, pl: `wynajem`, ipa: `la lo-ka-sją`}], phrases: [{fr: `À cette adresse, s’il vous plaît.`, pl: `Pod ten adres, proszę.`, ipa: `a set a-dres sil wu ple`},{fr: `Combien coûte le trajet ?`, pl: `Ile kosztuje przejazd?`, ipa: `ką-bję kut ly tra-że`},{fr: `C’est loin de l’aéroport ?`, pl: `Czy to daleko od lotniska?`, ipa: `se lwę dy la-e-ro-por`},{fr: `Je voudrais louer une voiture.`, pl: `Chciałbym wynająć samochód.`, ipa: `ży wu-dre lu-e iun wua-tiur`},{fr: `Vous pouvez attendre ici ?`, pl: `Czy może pan/pani poczekać tutaj?`, ipa: `wu pu-we a-tądr i-si`},{fr: `Je suis pressé.`, pl: `Spieszę się.`, ipa: `ży słi pre-se`}], grammar: `À cette adresse oznacza „pod ten adres” i jest idealne w taksówce. Louer znaczy „wynajmować”, a Je voudrais louer… to uprzejmy sposób rozpoczęcia rozmowy w wypożyczalni. Je suis pressé oznacza „spieszę się”; kobieta może powiedzieć pressée, ale wymowa jest podobna.`, practice: [`Powiedz taksówkarzowi: „Pod ten adres, proszę”.`,`Zapytaj o koszt przejazdu.`,`Powiedz, że spieszysz się.`,`Przetłumacz: Je voudrais louer une voiture.`,`Ułóż dialog z kierowcą taksówki.`]},{day: 23, title: `Zaproszenia i spotkania`, title_native: `Invitations et rendez-vous`, focus: `Poznajesz kogoś w Rennes i umawiasz się na kawę. Nauczysz się proponować spotkanie, potwierdzać godzinę i odmawiać uprzejmie.`, vocab: [{fr: `un rendez-vous`, pl: `spotkanie`, ipa: `ę rą-de-wu`},{fr: `rencontrer`, pl: `spotkać`, ipa: `rą-ką-tre`},{fr: `inviter`, pl: `zaprosić`, ipa: `ę-wi-te`},{fr: `disponible`, pl: `dostępny`, ipa: `dis-po-ni-bl`},{fr: `ce soir`, pl: `dziś wieczorem`, ipa: `sy słar`},{fr: `demain matin`, pl: `jutro rano`, ipa: `dy-mę ma-tę`},{fr: `d’accord`, pl: `zgoda`, ipa: `da-kor`},{fr: `peut-être`, pl: `może`, ipa: `py-tetr`},{fr: `désolé`, pl: `przepraszam/przykro mi`, ipa: `de-zo-le`},{fr: `volontiers`, pl: `chętnie`, ipa: `wo-lą-tje`}], phrases: [{fr: `Vous êtes disponible ce soir ?`, pl: `Czy jest pan/pani dostępny dziś wieczorem?`, ipa: `wu zet dis-po-ni-bl sy słar`},{fr: `On prend un café ?`, pl: `Wypijemy kawę?`, ipa: `ą prą ę ka-fe`},{fr: `Avec plaisir.`, pl: `Z przyjemnością.`, ipa: `a-wek ple-zir`},{fr: `Désolé, je ne peux pas.`, pl: `Przykro mi, nie mogę.`, ipa: `de-zo-le ży ny py pa`},{fr: `Peut-être demain ?`, pl: `Może jutro?`, ipa: `py-tetr dy-mę`},{fr: `À quelle heure ?`, pl: `O której godzinie?`, ipa: `a kel er`}], grammar: `On jest bardzo częste w mowie i może znaczyć „my”. On prend un café ? brzmi naturalnie i lekko, mniej formalnie niż Voulez-vous prendre un café ? Przy odmowie warto dodać désolé i zaproponować inną opcję.`, practice: [`Zaproponuj kawę.`,`Powiedz: „Z przyjemnością”.`,`Odmów uprzejmie.`,`Zapytaj: „O której godzinie?”`,`Ułóż krótką rozmowę o spotkaniu jutro rano.`]},{day: 24, title: `Rozmowa towarzyska`, title_native: `Conversation sociale`, focus: `Rozmawiasz z lokalną osobą w kawiarni w Namur. Nauczysz się prostych pytań o miasto, pracę, podróże i zainteresowania.`, vocab: [{fr: `vivre`, pl: `mieszkać`, ipa: `wiwr`},{fr: `travailler`, pl: `pracować`, ipa: `tra-wa-je`},{fr: `aimer`, pl: `lubić`, ipa: `e-me`},{fr: `voyager`, pl: `podróżować`, ipa: `wua-ja-że`},{fr: `la ville`, pl: `miasto`, ipa: `la wil`},{fr: `le quartier`, pl: `dzielnica`, ipa: `ly kar-tje`},{fr: `intéressant`, pl: `interesujący`, ipa: `ę-te-re-są`},{fr: `sympa`, pl: `fajny`, ipa: `sę-pa`},{fr: `souvent`, pl: `często`, ipa: `su-wą`},{fr: `parfois`, pl: `czasami`, ipa: `par-fła`}], phrases: [{fr: `Vous vivez ici ?`, pl: `Czy mieszka pan/pani tutaj?`, ipa: `wu wi-we i-si`},{fr: `J’aime beaucoup cette ville.`, pl: `Bardzo lubię to miasto.`, ipa: `żem bo-ku set wil`},{fr: `Vous travaillez ici ?`, pl: `Czy pracuje pan/pani tutaj?`, ipa: `wu tra-wa-je i-si`},{fr: `Je voyage souvent.`, pl: `Często podróżuję.`, ipa: `ży wua-jaż su-wą`},{fr: `Ce quartier est sympa.`, pl: `Ta dzielnica jest fajna.`, ipa: `sy kar-tje e sę-pa`},{fr: `C’est très intéressant.`, pl: `To bardzo interesujące.`, ipa: `se tre zę-te-re-są`}], grammar: `Czasowniki regularne zakończone na -er, takie jak aimer, voyager, travailler, mają wiele podobnych form. Na poziomie podróżnym najważniejsze jest znać gotowe zwroty: J’aime, je voyage, vous travaillez. Słowo sympa jest potoczne, ale bardzo popularne i przyjazne.`, practice: [`Powiedz, że lubisz to miasto.`,`Zapytaj, czy ktoś mieszka tutaj.`,`Powiedz, że często podróżujesz.`,`Przetłumacz: Ce quartier est sympa.`,`Napisz trzy pytania do lokalnej osoby.`]},{day: 25, title: `W domu i mieszkaniu`, title_native: `Dans la maison et l’appartement`, focus: `Wynajmujesz apartament w Paryżu lub na Airbnb w Lyonie. Nauczysz się mówić o pokoju, kuchni, łazience i problemach z wyposażeniem.`, vocab: [{fr: `un appartement`, pl: `mieszkanie`, ipa: `ę na-par-ty-mą`},{fr: `une maison`, pl: `dom`, ipa: `iun me-zą`},{fr: `la chambre`, pl: `sypialnia/pokój`, ipa: `la sząbr`},{fr: `la cuisine`, pl: `kuchnia`, ipa: `la kui-zin`},{fr: `la salle de bain`, pl: `łazienka`, ipa: `la sal dy bę`},{fr: `la porte`, pl: `drzwi`, ipa: `la port`},{fr: `la fenêtre`, pl: `okno`, ipa: `la fy-netr`},{fr: `la lumière`, pl: `światło`, ipa: `la liu-mjer`},{fr: `la clé`, pl: `klucz`, ipa: `la kle`},{fr: `cassé`, pl: `zepsuty`, ipa: `ka-se`}], phrases: [{fr: `La clé ne marche pas.`, pl: `Klucz nie działa.`, ipa: `la kle ny marsz pa`},{fr: `La lumière est cassée.`, pl: `Światło jest zepsute.`, ipa: `la liu-mjer e ka-se`},{fr: `Où est la salle de bain ?`, pl: `Gdzie jest łazienka?`, ipa: `u e la sal dy bę`},{fr: `La cuisine est équipée ?`, pl: `Czy kuchnia jest wyposażona?`, ipa: `la kui-zin e e-ki-pe`},{fr: `Il y a un problème avec la porte.`, pl: `Jest problem z drzwiami.`, ipa: `il ja ę pro-blem a-wek la port`},{fr: `L’appartement est propre.`, pl: `Mieszkanie jest czyste.`, ipa: `la-par-ty-mą e propr`}], grammar: `Il y a oznacza „jest” lub „są” i bardzo pomaga w opisywaniu problemów: Il y a un problème. Ne marche pas znaczy „nie działa”, dosłownie „nie chodzi”. W praktyce możesz użyć tego zwrotu dla klucza, telefonu, Wi-Fi czy automatu.`, practice: [`Powiedz, że klucz nie działa.`,`Zapytaj, gdzie jest łazienka.`,`Przetłumacz: L’appartement est propre.`,`Powiedz, że jest problem z drzwiami.`,`Opisz wynajęte mieszkanie trzema zdaniami.`]},{day: 26, title: `Formalności i dokumenty`, title_native: `Formalités et documents`, focus: `Potrzebujesz pomocy z dokumentami przy recepcji, wypożyczalni lub kontroli. Nauczysz się mówić o paszporcie, dowodzie i podpisie.`, vocab: [{fr: `un document`, pl: `dokument`, ipa: `ę do-kiu-mą`},{fr: `le passeport`, pl: `paszport`, ipa: `ly pas-por`},{fr: `la carte d’identité`, pl: `dowód osobisty`, ipa: `la kart di-dą-ti-te`},{fr: `le permis de conduire`, pl: `prawo jazdy`, ipa: `ly per-mi dy ką-diu-ir`},{fr: `la signature`, pl: `podpis`, ipa: `la si-ńa-tiur`},{fr: `signer`, pl: `podpisać`, ipa: `si-ńe`},{fr: `remplir`, pl: `wypełnić`, ipa: `rą-plir`},{fr: `le formulaire`, pl: `formularz`, ipa: `ly for-miu-ler`},{fr: `valide`, pl: `ważny`, ipa: `wa-lid`},{fr: `une copie`, pl: `kopia`, ipa: `iun ko-pi`}], phrases: [{fr: `Voici mon passeport.`, pl: `Oto mój paszport.`, ipa: `wła-si mą pas-por`},{fr: `Il faut signer ici.`, pl: `Trzeba podpisać tutaj.`, ipa: `il fo si-ńe i-si`},{fr: `Je dois remplir ce formulaire ?`, pl: `Czy muszę wypełnić ten formularz?`, ipa: `ży dwa rą-plir sy for-miu-ler`},{fr: `Vous avez une copie ?`, pl: `Czy ma pan/pani kopię?`, ipa: `wu za-we iun ko-pi`},{fr: `Ma carte est valide.`, pl: `Mój dokument jest ważny.`, ipa: `ma kart e wa-lid`},{fr: `J’ai mon permis de conduire.`, pl: `Mam prawo jazdy.`, ipa: `że mą per-mi dy ką-diu-ir`}], grammar: `Il faut + bezokolicznik oznacza „trzeba coś zrobić”, np. Il faut signer. Je dois oznacza „muszę” i jest bardziej osobiste: Je dois remplir ce formulaire ? W formalnych sytuacjach mów spokojnie i używaj voici, gdy podajesz dokument.`, practice: [`Powiedz: „Oto mój paszport”.`,`Zapytaj, czy musisz wypełnić formularz.`,`Przetłumacz: Il faut signer ici.`,`Powiedz, że masz prawo jazdy.`,`Ułóż krótką rozmowę w wypożyczalni samochodów.`]},{day: 27, title: `Bezpieczeństwo i sytuacje awaryjne`, title_native: `Sécurité et urgences`, focus: `W razie problemu w mieście musisz wezwać pomoc albo zgłosić zgubiony portfel. Nauczysz się prostych, jasnych zwrotów awaryjnych.`, vocab: [{fr: `la sécurité`, pl: `bezpieczeństwo`, ipa: `la se-kiu-ri-te`},{fr: `une urgence`, pl: `nagły wypadek`, ipa: `iun iur-żans`},{fr: `la police`, pl: `policja`, ipa: `la po-lis`},{fr: `un hôpital`, pl: `szpital`, ipa: `ę no-pi-tal`},{fr: `un portefeuille`, pl: `portfel`, ipa: `ę port-fey`},{fr: `perdre`, pl: `zgubić`, ipa: `perdr`},{fr: `volé`, pl: `skradziony`, ipa: `wo-le`},{fr: `dangereux`, pl: `niebezpieczny`, ipa: `dą-ży-rø`},{fr: `aider`, pl: `pomóc`, ipa: `e-de`},{fr: `appeler`, pl: `zadzwonić`, ipa: `a-py-le`}], phrases: [{fr: `C’est une urgence.`, pl: `To nagły wypadek.`, ipa: `se tiun iur-żans`},{fr: `Appelez la police, s’il vous plaît.`, pl: `Proszę zadzwonić na policję.`, ipa: `a-py-le la po-lis sil wu ple`},{fr: `J’ai perdu mon portefeuille.`, pl: `Zgubiłem portfel.`, ipa: `że per-diu mą port-fey`},{fr: `Mon sac a été volé.`, pl: `Moja torba została skradziona.`, ipa: `mą sak a e-te wo-le`},{fr: `Où est l’hôpital ?`, pl: `Gdzie jest szpital?`, ipa: `u e lo-pi-tal`},{fr: `J’ai besoin d’aide.`, pl: `Potrzebuję pomocy.`, ipa: `że by-zwę ded`}], grammar: `J’ai besoin de… oznacza „potrzebuję…”. Przed samogłoską de skraca się do d’, jak w d’aide. W sytuacjach awaryjnych używaj krótkich zdań i powtarzaj kluczowe informacje: police, hôpital, urgence.`, practice: [`Powiedz, że potrzebujesz pomocy.`,`Powiedz, że zgubiłeś portfel.`,`Poproś kogoś, żeby zadzwonił na policję.`,`Przetłumacz: C’est une urgence.`,`Napisz trzy zdania, których użyjesz w sytuacji awaryjnej.`]},{day: 28, title: `Opinie i porównania`, title_native: `Opinions et comparaisons`, focus: `Rozmawiasz o podróży, jedzeniu i miejscach z innymi turystami w Nicei. Nauczysz się mówić, co lubisz, czego nie lubisz i co jest lepsze.`, vocab: [{fr: `j’aime`, pl: `lubię`, ipa: `żem`},{fr: `je n’aime pas`, pl: `nie lubię`, ipa: `ży nem pa`},{fr: `préférer`, pl: `woleć`, ipa: `pre-fe-re`},{fr: `meilleur`, pl: `lepszy`, ipa: `me-jer`},{fr: `pire`, pl: `gorszy`, ipa: `pir`},{fr: `beau`, pl: `piękny`, ipa: `bo`},{fr: `bon`, pl: `dobry`, ipa: `bą`},{fr: `mauvais`, pl: `zły`, ipa: `mo-we`},{fr: `intéressant`, pl: `interesujący`, ipa: `ę-te-re-są`},{fr: `agréable`, pl: `przyjemny`, ipa: `a-gre-abl`}], phrases: [{fr: `J’aime cette ville.`, pl: `Lubię to miasto.`, ipa: `żem set wil`},{fr: `Je n’aime pas ce restaurant.`, pl: `Nie lubię tej restauracji.`, ipa: `ży nem pa sy res-to-rą`},{fr: `Je préfère le train.`, pl: `Wolę pociąg.`, ipa: `ży pre-fer ly trę`},{fr: `C’est meilleur ici.`, pl: `Tutaj jest lepiej.`, ipa: `se me-jer i-si`},{fr: `C’est plus cher.`, pl: `To jest droższe.`, ipa: `se pliu szer`},{fr: `C’est très agréable.`, pl: `To bardzo przyjemne.`, ipa: `se tre za-gre-abl`}], grammar: `Plus oznacza „bardziej” i tworzy proste porównania: plus cher, plus grand, plus intéressant. Meilleur znaczy „lepszy” i jest nieregularną formą od bon. Do wyrażania opinii wystarczy J’aime, Je n’aime pas i Je préfère.`, practice: [`Powiedz, że lubisz to miasto.`,`Powiedz, że wolisz pociąg.`,`Przetłumacz: C’est plus cher.`,`Porównaj dwie kawiarnie prostym zdaniem.`,`Napisz trzy opinie o podróży po francusku.`]},{day: 29, title: `Planowanie kolejnych dni`, title_native: `Organiser les prochains jours`, focus: `Układasz plan podróży po Francji: dziś Paryż, jutro Lyon, potem Nicea. Nauczysz się mówić o zamiarach i kolejności działań.`, vocab: [{fr: `organiser`, pl: `organizować`, ipa: `or-ga-ni-ze`},{fr: `prévoir`, pl: `planować`, ipa: `pre-włar`},{fr: `d’abord`, pl: `najpierw`, ipa: `da-bor`},{fr: `ensuite`, pl: `potem`, ipa: `ą-słit`},{fr: `après`, pl: `później`, ipa: `a-pre`},{fr: `avant`, pl: `przed`, ipa: `a-wą`},{fr: `pendant`, pl: `podczas`, ipa: `pą-dą`},{fr: `le voyage`, pl: `podróż`, ipa: `ly wua-jaż`},{fr: `le séjour`, pl: `pobyt`, ipa: `ly se-żur`},{fr: `prochain`, pl: `następny`, ipa: `pro-szę`}], phrases: [{fr: `Je vais visiter Lyon demain.`, pl: `Jutro odwiedzę Lyon.`, ipa: `ży we wi-zi-te li-ją dy-mę`},{fr: `D’abord, je vais au musée.`, pl: `Najpierw idę do muzeum.`, ipa: `da-bor ży we o miu-ze`},{fr: `Ensuite, je prends le train.`, pl: `Potem jadę pociągiem.`, ipa: `ą-słit ży prą ly trę`},{fr: `Après, je vais à l’hôtel.`, pl: `Później idę do hotelu.`, ipa: `a-pre ży we a lo-tel`},{fr: `Je reste trois jours.`, pl: `Zostaję trzy dni.`, ipa: `ży rest trwa żur`},{fr: `Mon prochain arrêt est Nice.`, pl: `Mój następny przystanek to Nicea.`, ipa: `mą pro-szę na-re e nis`}], grammar: `Je vais + bezokolicznik tworzy bardzo prosty czas przyszły: Je vais visiter, Je vais manger. To idealna konstrukcja dla podróżnych, bo pozwala mówić o planach bez skomplikowanej gramatyki. D’abord, ensuite i après pomagają opowiadać wydarzenia w kolejności.`, practice: [`Powiedz, że jutro odwiedzisz Lyon.`,`Użyj d’abord i ensuite w dwóch zdaniach.`,`Powiedz, że zostajesz trzy dni.`,`Przetłumacz: Mon prochain arrêt est Nice.`,`Napisz krótki plan podróży na jutro.`]},{day: 30, title: `Powtórka podróżna i pewność w rozmowie`, title_native: `Révision de voyage et confiance`, focus: `Kończysz kurs i przygotowujesz się do realnych rozmów w krajach francuskojęzycznych. Połączysz powitania, pytania, zamówienia, transport, hotel i sytuacje awaryjne.`, vocab: [{fr: `réviser`, pl: `powtarzać`, ipa: `re-wi-ze`},{fr: `parler`, pl: `mówić`, ipa: `par-le`},{fr: `écouter`, pl: `słuchać`, ipa: `e-ku-te`},{fr: `demander`, pl: `pytać/prosić`, ipa: `dy-mą-de`},{fr: `répondre`, pl: `odpowiadać`, ipa: `re-pądr`},{fr: `voyageur`, pl: `podróżny`, ipa: `wua-ja-żer`},{fr: `voyageuse`, pl: `podróżna`, ipa: `wua-ja-żez`},{fr: `facile`, pl: `łatwy`, ipa: `fa-sil`},{fr: `difficile`, pl: `trudny`, ipa: `di-fi-sil`},{fr: `confiance`, pl: `pewność siebie`, ipa: `ką-fjąs`}], phrases: [{fr: `Je parle un peu français.`, pl: `Mówię trochę po francusku.`, ipa: `ży parl ę py frą-se`},{fr: `Pouvez-vous parler lentement ?`, pl: `Czy może pan/pani mówić powoli?`, ipa: `pu-we wu par-le ląt-mą`},{fr: `Je comprends un peu.`, pl: `Trochę rozumiem.`, ipa: `ży ką-prą ę py`},{fr: `Je ne comprends pas encore.`, pl: `Jeszcze nie rozumiem.`, ipa: `ży ny ką-prą pa ą-kor`},{fr: `Je peux essayer en français ?`, pl: `Czy mogę spróbować po francusku?`, ipa: `ży py e-se-je ą frą-se`},{fr: `Merci pour votre aide.`, pl: `Dziękuję za pomoc.`, ipa: `mer-si pur wo-tr ed`}], grammar: `Un peu oznacza „trochę” i jest bardzo przydatne, gdy chcesz mówić realistycznie o swoim poziomie. Encore może znaczyć „jeszcze”, jak w pas encore, czyli „jeszcze nie”. Najważniejsza strategia podróżna to mówić prosto, grzecznie i prosić o powtórzenie.`, practice: [`Powiedz, że mówisz trochę po francusku.`,`Poproś, by ktoś mówił powoli.`,`Powiedz, że jeszcze nie rozumiesz.`,`Podziękuj za pomoc.`,`Napisz pięciozdaniową rozmowę łączącą hotel, kawiarnię i transport.`]}];

var CONVERSATIONS_PL_FR = [{id: 1, title: `Zamawianie w kawiarni`, scene: `Jesteś w małej kawiarni w Paryżu rano. Chcesz zamówić kawę, rogalika i szklankę wody, a potem zapłacić kartą.`, lines: [{who: `them`, fr: `Bonjour, monsieur, vous désirez ?`, pl: `Dzień dobry, proszę pana, co pan sobie życzy?`},{who: `you`, fr: `Bonjour, je voudrais un café, s’il vous plaît.`, pl: `Dzień dobry, chciałbym kawę, proszę.`},{who: `them`, fr: `Bien sûr, avec du lait ou sans lait ?`, pl: `Oczywiście, z mlekiem czy bez mleka?`},{who: `you`, fr: `Sans lait, mais avec un peu de sucre.`, pl: `Bez mleka, ale z odrobiną cukru.`},{who: `them`, fr: `Très bien, autre chose ?`, pl: `Dobrze, coś jeszcze?`},{who: `you`, fr: `Oui, un croissant et un verre d’eau, s’il vous plaît.`, pl: `Tak, rogalika i szklankę wody, proszę.`},{who: `them`, fr: `Voilà, ça fait six euros.`, pl: `Proszę, to będzie sześć euro.`},{who: `you`, fr: `Je peux payer par carte ?`, pl: `Czy mogę zapłacić kartą?`},{who: `them`, fr: `Oui, bien sûr.`, pl: `Tak, oczywiście.`},{who: `you`, fr: `Merci beaucoup.`, pl: `Bardzo dziękuję.`},{who: `them`, fr: `Merci à vous, bonne journée.`, pl: `Dziękuję panu, miłego dnia.`}]},{id: 2, title: `Meldunek w hotelu`, scene: `Przyjeżdżasz wieczorem do hotelu w Lyonie. Masz rezerwację i chcesz zapytać o śniadanie oraz hasło do Wi-Fi.`, lines: [{who: `them`, fr: `Bonsoir, bienvenue à l’hôtel Lumière.`, pl: `Dobry wieczór, witamy w hotelu Lumière.`},{who: `you`, fr: `Bonsoir, j’ai une réservation.`, pl: `Dobry wieczór, mam rezerwację.`},{who: `them`, fr: `À quel nom, s’il vous plaît ?`, pl: `Na jakie nazwisko, proszę?`},{who: `you`, fr: `Au nom de Kowalski.`, pl: `Na nazwisko Kowalski.`},{who: `them`, fr: `Très bien, puis-je voir votre passeport ?`, pl: `Dobrze, czy mogę zobaczyć pana paszport?`},{who: `you`, fr: `Oui, voici mon passeport.`, pl: `Tak, oto mój paszport.`},{who: `them`, fr: `Votre chambre est au deuxième étage.`, pl: `Pański pokój jest na drugim piętrze.`},{who: `you`, fr: `Merci, le petit-déjeuner est inclus ?`, pl: `Dziękuję, czy śniadanie jest wliczone?`},{who: `them`, fr: `Oui, de sept heures à dix heures.`, pl: `Tak, od siódmej do dziesiątej.`},{who: `you`, fr: `Quel est le mot de passe du Wi-Fi ?`, pl: `Jakie jest hasło do Wi-Fi?`},{who: `them`, fr: `C’est bienvenue2026.`, pl: `To bienvenue2026.`},{who: `you`, fr: `Merci pour votre aide.`, pl: `Dziękuję za pomoc.`}]},{id: 3, title: `Pytanie o drogę`, scene: `Jesteś w Genewie i szukasz dworca. Zatrzymujesz przechodnia i prosisz o proste wskazówki, bo nie znasz dobrze miasta.`, lines: [{who: `you`, fr: `Excusez-moi, où est la gare ?`, pl: `Przepraszam, gdzie jest dworzec?`},{who: `them`, fr: `La gare est près d’ici.`, pl: `Dworzec jest blisko stąd.`},{who: `you`, fr: `Je dois aller tout droit ?`, pl: `Czy muszę iść prosto?`},{who: `them`, fr: `Oui, allez tout droit jusqu’au pont.`, pl: `Tak, proszę iść prosto aż do mostu.`},{who: `you`, fr: `Et après le pont ?`, pl: `A po moście?`},{who: `them`, fr: `Tournez à droite, puis à gauche.`, pl: `Proszę skręcić w prawo, potem w lewo.`},{who: `you`, fr: `C’est loin ?`, pl: `Czy to daleko?`},{who: `them`, fr: `Non, environ cinq minutes à pied.`, pl: `Nie, około pięciu minut pieszo.`},{who: `you`, fr: `Pouvez-vous répéter lentement ?`, pl: `Czy może pan/pani powtórzyć powoli?`},{who: `them`, fr: `Tout droit, à droite, puis à gauche.`, pl: `Prosto, w prawo, potem w lewo.`},{who: `you`, fr: `Merci beaucoup.`, pl: `Bardzo dziękuję.`},{who: `them`, fr: `Avec plaisir.`, pl: `Z przyjemnością.`}]},{id: 4, title: `Kolacja w restauracji`, scene: `Jesteś w restauracji w Bordeaux. Chcesz zapytać o rekomendację, zamówić danie bez mięsa i poprosić o rachunek.`, lines: [{who: `them`, fr: `Bonsoir, vous avez choisi ?`, pl: `Dobry wieczór, czy państwo wybrali?`},{who: `you`, fr: `Pas encore, qu’est-ce que vous recommandez ?`, pl: `Jeszcze nie, co pan/pani poleca?`},{who: `them`, fr: `Le poisson est excellent ce soir.`, pl: `Ryba jest dziś wieczorem znakomita.`},{who: `you`, fr: `Je ne mange pas de viande, mais je mange du poisson.`, pl: `Nie jem mięsa, ale jem ryby.`},{who: `them`, fr: `Alors le poisson avec des légumes est parfait.`, pl: `W takim razie ryba z warzywami będzie idealna.`},{who: `you`, fr: `Très bien, je prends le poisson.`, pl: `Dobrze, biorę rybę.`},{who: `them`, fr: `Vous voulez une entrée ?`, pl: `Czy chce pan/pani przystawkę?`},{who: `you`, fr: `Oui, une soupe, s’il vous plaît.`, pl: `Tak, zupę, proszę.`},{who: `them`, fr: `Très bien, et comme boisson ?`, pl: `Dobrze, a do picia?`},{who: `you`, fr: `Un verre d’eau, s’il vous plaît.`, pl: `Szklankę wody, proszę.`},{who: `them`, fr: `Bien sûr.`, pl: `Oczywiście.`},{who: `you`, fr: `Plus tard, l’addition, s’il vous plaît.`, pl: `Później rachunek, proszę.`}]},{id: 5, title: `Kupowanie biletu na metro`, scene: `Jesteś przy automacie biletowym w Paryżu, ale nie jesteś pewien, który bilet wybrać. Prosisz pracownika stacji o pomoc.`, lines: [{who: `them`, fr: `Bonjour, vous avez besoin d’aide ?`, pl: `Dzień dobry, czy potrzebuje pan/pani pomocy?`},{who: `you`, fr: `Oui, je voudrais un billet pour le centre.`, pl: `Tak, chciałbym bilet do centrum.`},{who: `them`, fr: `Vous prenez le métro ou le bus ?`, pl: `Bierze pan/pani metro czy autobus?`},{who: `you`, fr: `Le métro, s’il vous plaît.`, pl: `Metro, proszę.`},{who: `them`, fr: `Prenez un ticket simple.`, pl: `Proszę wziąć bilet jednorazowy.`},{who: `you`, fr: `Quelle ligne pour le Louvre ?`, pl: `Która linia do Luwru?`},{who: `them`, fr: `Prenez la ligne un.`, pl: `Proszę wziąć linię pierwszą.`},{who: `you`, fr: `Je dois descendre où ?`, pl: `Gdzie muszę wysiąść?`},{who: `them`, fr: `Descendez à Palais Royal.`, pl: `Proszę wysiąść na Palais Royal.`},{who: `you`, fr: `C’est direct ?`, pl: `Czy to bezpośrednio?`},{who: `them`, fr: `Oui, c’est direct.`, pl: `Tak, bezpośrednio.`},{who: `you`, fr: `Merci beaucoup.`, pl: `Bardzo dziękuję.`}]},{id: 6, title: `Zakupy w sklepie z ubraniami`, scene: `Jesteś w sklepie w Lille i szukasz koszuli w odpowiednim rozmiarze. Chcesz przymierzyć jedną rzecz i zapytać o inny kolor.`, lines: [{who: `them`, fr: `Bonjour, je peux vous aider ?`, pl: `Dzień dobry, czy mogę pomóc?`},{who: `you`, fr: `Oui, je cherche une chemise.`, pl: `Tak, szukam koszuli.`},{who: `them`, fr: `Quelle taille ?`, pl: `Jaki rozmiar?`},{who: `you`, fr: `Vous avez ma taille, moyen ?`, pl: `Czy macie mój rozmiar, średni?`},{who: `them`, fr: `Oui, voici une chemise bleue.`, pl: `Tak, oto niebieska koszula.`},{who: `you`, fr: `Je peux essayer ?`, pl: `Czy mogę przymierzyć?`},{who: `them`, fr: `Bien sûr, les cabines sont là.`, pl: `Oczywiście, przymierzalnie są tam.`},{who: `you`, fr: `C’est un peu trop grand.`, pl: `Jest trochę za duża.`},{who: `them`, fr: `Je peux vous donner une taille plus petite.`, pl: `Mogę podać mniejszy rozmiar.`},{who: `you`, fr: `Vous avez une autre couleur ?`, pl: `Czy macie inny kolor?`},{who: `them`, fr: `Oui, en blanc et en noir.`, pl: `Tak, białą i czarną.`},{who: `you`, fr: `Je prends la blanche.`, pl: `Biorę białą.`}]},{id: 7, title: `W aptece`, scene: `Jesteś w Tuluzie i boli cię gardło. Wchodzisz do apteki, żeby poprosić o coś prostego i zapytać, jak to stosować.`, lines: [{who: `them`, fr: `Bonjour, monsieur, que puis-je faire pour vous ?`, pl: `Dzień dobry, proszę pana, co mogę dla pana zrobić?`},{who: `you`, fr: `Bonjour, j’ai mal à la gorge.`, pl: `Dzień dobry, boli mnie gardło.`},{who: `them`, fr: `Vous avez de la fièvre ?`, pl: `Czy ma pan gorączkę?`},{who: `you`, fr: `Non, je n’ai pas de fièvre.`, pl: `Nie, nie mam gorączki.`},{who: `them`, fr: `Vous avez aussi un rhume ?`, pl: `Czy ma pan też przeziębienie?`},{who: `you`, fr: `Oui, un peu.`, pl: `Tak, trochę.`},{who: `them`, fr: `Je vous conseille ce médicament.`, pl: `Polecam panu ten lek.`},{who: `you`, fr: `Comment je dois le prendre ?`, pl: `Jak mam go brać?`},{who: `them`, fr: `Deux fois par jour, après le repas.`, pl: `Dwa razy dziennie, po posiłku.`},{who: `you`, fr: `Vous avez aussi des pansements ?`, pl: `Czy macie też plastry?`},{who: `them`, fr: `Oui, bien sûr.`, pl: `Tak, oczywiście.`},{who: `you`, fr: `Merci, c’est tout.`, pl: `Dziękuję, to wszystko.`}]},{id: 8, title: `Rozmowa z lokalną osobą`, scene: `Siedzisz na ławce w parku w Montrealu i zaczynasz lekką rozmowę z lokalną osobą. Chcesz poćwiczyć francuski i zapytać o miasto.`, lines: [{who: `you`, fr: `Bonjour, je peux m’asseoir ici ?`, pl: `Dzień dobry, czy mogę tu usiąść?`},{who: `them`, fr: `Oui, bien sûr.`, pl: `Tak, oczywiście.`},{who: `you`, fr: `Merci, je visite Montréal pour la première fois.`, pl: `Dziękuję, odwiedzam Montreal po raz pierwszy.`},{who: `them`, fr: `Bienvenue, vous aimez la ville ?`, pl: `Witamy, podoba się panu/pani miasto?`},{who: `you`, fr: `Oui, j’aime beaucoup cette ville.`, pl: `Tak, bardzo lubię to miasto.`},{who: `them`, fr: `Vous venez d’où ?`, pl: `Skąd pan/pani jest?`},{who: `you`, fr: `Je viens de Pologne.`, pl: `Pochodzę z Polski.`},{who: `them`, fr: `Ah, très bien, vous parlez français ?`, pl: `Ach, bardzo dobrze, mówi pan/pani po francusku?`},{who: `you`, fr: `Je parle un peu français.`, pl: `Mówię trochę po francusku.`},{who: `them`, fr: `Vous vous débrouillez très bien.`, pl: `Radzi pan/pani sobie bardzo dobrze.`},{who: `you`, fr: `Merci, c’est très gentil.`, pl: `Dziękuję, to bardzo miłe.`},{who: `them`, fr: `Profitez bien de votre séjour.`, pl: `Proszę dobrze wykorzystać swój pobyt.`}]}];